/* Módulo de matices de verbos — Japanese N1 Path
   Grupos de verbos que significan lo mismo pero cambian de registro o de transitividad.
   Categorias: keigo (registros de cortesia), jita (transitivo/intransitivo), tsukaiwake (matices de uso).
   Cada entrada: id, cat, lvl, title, sub, intro, rows[{tag,lbl,jp,rd,when,ex,exr,ext}], note, err. */
window.TIPS = [
{"id":"keigo-iku","cat":"keigo","lvl":"N4","title":"行く — ir","sub":"El mismo desplazamiento en cuatro registros","intro":"El japonés no cambia solo la terminación: para los verbos más usados existe una palabra distinta según a quién respetas. Con 行く, la clave es quién se mueve: si es la persona a la que respetas, usas 尊敬語; si eres tú acercándote a ella, 謙譲語.","rows":[{"tag":"普通形","lbl":"Informal","jp":"行く","rd":"いく","when":"Con amigos, familia o en un diario. También dentro de frases subordinadas, incluso en contextos formales.","ex":"明日、大阪に行く。","exr":"あした、おおさかに いく","ext":"Mañana voy a Osaka."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"行きます","rd":"いきます","when":"Registro cortés por defecto: con desconocidos, compañeros o clientes. No eleva ni rebaja a nadie, solo es educado.","ex":"明日、大阪に行きます。","exr":"あした、おおさかに いきます","ext":"Mañana voy a Osaka."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"いらっしゃる／おいでになる","rd":"いらっしゃる／おいでになる","when":"Quien va es tu superior o cliente. Nunca lo uses para ti mismo.","ex":"部長は明日、大阪にいらっしゃいます。","exr":"ぶちょうは あした、おおさかに いらっしゃいます","ext":"El jefe de sección irá mañana a Osaka."},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"参る／伺う","rd":"まいる／うかがう","when":"Quien va eres tú, y te humillas ante el interlocutor. 伺う solo si vas al lugar de la persona respetada; 参る sirve siempre.","ex":"三時に御社へ伺います。","exr":"さんじに おんしゃへ うかがいます","ext":"Iré a su empresa a las tres."}],"note":"いらっしゃる es irregular en -masu: いらっしゃります ✗ → いらっしゃいます ✓. Lo mismo con おっしゃる, くださる, なさる y ござる.","err":"Decir 私が大阪にいらっしゃいます. Nunca te eleves a ti mismo: es 参ります."},
{"id":"keigo-kuru","cat":"keigo","lvl":"N4","title":"来る — venir","sub":"Comparte 尊敬語 con 行く, pero añade formas propias","intro":"来る usa las mismas palabras que 行く en 尊敬語 (いらっしゃる) y 謙譲語 (参る). La diferencia es que, para 'venir', el japonés dispone de fórmulas extra muy usadas en el trato comercial.","rows":[{"tag":"普通形","lbl":"Informal","jp":"来る","rd":"くる","when":"Con gente de confianza.","ex":"友達が家に来る。","exr":"ともだちが いえに くる","ext":"Un amigo viene a casa."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"来ます","rd":"きます","when":"Registro cortés estándar.","ex":"友達が家に来ます。","exr":"ともだちが いえに きます","ext":"Un amigo viene a casa."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"いらっしゃる／お見えになる／お越しになる","rd":"いらっしゃる／おみえになる／おこしになる","when":"Viene tu superior o un cliente. お見えになる y お越しになる son típicas al recibir visitas.","ex":"お客様がお見えになりました。","exr":"おきゃくさまが おみえに なりました","ext":"Ha llegado el cliente."},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"参る","rd":"まいる","when":"Vienes tú ante alguien a quien respetas.","ex":"すぐに参ります。","exr":"すぐに まいります","ext":"Voy enseguida."}],"note":"En un anuncio (tren, tienda) oirás 電車が参ります: aquí 参る no rebaja al tren, sino que muestra respeto hacia el público que escucha.","err":"Usar 来られる (potencial/pasiva) creyendo que es 尊敬語. Existe como respetuoso, pero es ambiguo: mejor いらっしゃる."},
{"id":"keigo-iru","cat":"keigo","lvl":"N4","title":"いる — estar (personas)","sub":"Presencia: いらっしゃる frente a おる","intro":"Para decir que alguien está en un sitio, el registro cambia por completo la palabra. おる es la forma humilde, y también aparece como auxiliar (〜ております) en el lenguaje de empresa.","rows":[{"tag":"普通形","lbl":"Informal","jp":"いる","rd":"いる","when":"Con confianza.","ex":"父は家にいる。","exr":"ちちは いえに いる","ext":"Mi padre está en casa."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"います","rd":"います","when":"Cortesía estándar.","ex":"父は家にいます。","exr":"ちちは いえに います","ext":"Mi padre está en casa."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"いらっしゃる","rd":"いらっしゃる","when":"Está tu superior o tu cliente.","ex":"社長は会議室にいらっしゃいます。","exr":"しゃちょうは かいぎしつに いらっしゃいます","ext":"El presidente está en la sala de reuniones."},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"おる","rd":"おる","when":"Estás tú, o alguien de tu grupo (tu empresa, tu familia) visto desde fuera.","ex":"担当者はただ今席におりません。","exr":"たんとうしゃは ただいま せきに おりません","ext":"El encargado no está ahora en su sitio."}],"note":"〜ております es el equivalente humilde de 〜ています: 検討しております (lo estamos estudiando). Es la fórmula reina del japonés de negocios.","err":"Decirle a un cliente 部長はいらっしゃいません. Tu jefe pertenece a TU grupo: ante el cliente se rebaja → 部長はおりません."},
{"id":"keigo-iu","cat":"keigo","lvl":"N4","title":"言う — decir","sub":"おっしゃる · 申す · 申し上げる","intro":"言う tiene dos formas humildes distintas, y elegir mal suena raro: 申す solo declara, 申し上げる dirige la palabra a alguien concreto a quien respetas.","rows":[{"tag":"普通形","lbl":"Informal","jp":"言う","rd":"いう","when":"Con confianza.","ex":"彼はそう言った。","exr":"かれは そう いった","ext":"Él dijo eso."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"言います","rd":"いいます","when":"Cortesía estándar.","ex":"彼はそう言いました。","exr":"かれは そう いいました","ext":"Él dijo eso."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"おっしゃる","rd":"おっしゃる","when":"Habla tu superior o tu cliente.","ex":"先生がおっしゃったとおりです。","exr":"せんせいが おっしゃった とおりです","ext":"Es tal y como dijo el profesor."},{"tag":"謙譲語 I","lbl":"Muy formal · hacia un destinatario","jp":"申し上げる","rd":"もうしあげる","when":"Le dices algo a la persona respetada. Fórmulas fijas: お礼申し上げます, お詫び申し上げます.","ex":"心よりお礼申し上げます。","exr":"こころより おれい もうしあげます","ext":"Le doy las gracias de corazón."},{"tag":"謙譲語 II","lbl":"Muy formal · simple declaración","jp":"申す","rd":"もうす","when":"Presentarte o declarar algo con humildad, sin dirigirte a un superior en concreto.","ex":"田中と申します。","exr":"たなかと もうします","ext":"Me llamo Tanaka."}],"note":"Regla práctica: 申し上げる cuando hay un destinatario respetado (お礼申し上げます); 申す cuando solo describes (田中と申します).","err":"Decir 社長が申しました ante un cliente está BIEN (tu jefe es de tu grupo), pero 先生が申しました está MAL: al profesor lo elevas → おっしゃいました."},
{"id":"keigo-taberu","cat":"keigo","lvl":"N4","title":"食べる・飲む — comer y beber","sub":"召し上がる · いただく","intro":"Un mismo par de verbos cubre comer y beber en keigo: 召し上がる para quien respetas, いただく para ti. いただく es además el verbo más versátil del japonés cortés.","rows":[{"tag":"普通形","lbl":"Informal","jp":"食べる／飲む","rd":"たべる／のむ","when":"Con confianza.","ex":"もうお昼を食べた？","exr":"もう おひるを たべた？","ext":"¿Ya has comido?"},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"食べます／飲みます","rd":"たべます／のみます","when":"Cortesía estándar.","ex":"毎朝コーヒーを飲みます。","exr":"まいあさ コーヒーを のみます","ext":"Bebo café cada mañana."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"召し上がる","rd":"めしあがる","when":"Come o bebe la persona respetada. Ofrecer: どうぞ召し上がってください.","ex":"どうぞ、温かいうちに召し上がってください。","exr":"どうぞ、あたたかい うちに めしあがって ください","ext":"Por favor, cómalo mientras está caliente."},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"いただく","rd":"いただく","when":"Comes o bebes tú. De ahí viene el いただきます antes de comer.","ex":"おいしくいただきました。","exr":"おいしく いただきました","ext":"Lo he comido con mucho gusto."}],"note":"お召し上がりください es muy común en tiendas. Puristas lo llaman doble keigo, pero está plenamente aceptado.","err":"Preguntar a un cliente 食べますか es demasiado plano: 召し上がりますか."},
{"id":"keigo-miru","cat":"keigo","lvl":"N4","title":"見る — ver","sub":"ご覧になる · 拝見する","intro":"拝見する es de los humildes más usados en el trabajo: cada vez que abres un correo o revisas un documento de un superior.","rows":[{"tag":"普通形","lbl":"Informal","jp":"見る","rd":"みる","when":"Con confianza.","ex":"その映画、もう見た。","exr":"その えいが、もう みた","ext":"Esa película ya la he visto."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"見ます","rd":"みます","when":"Cortesía estándar.","ex":"あとで資料を見ます。","exr":"あとで しりょうを みます","ext":"Miraré el documento después."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"ご覧になる","rd":"ごらんになる","when":"Mira la persona respetada. Invitación: ご覧ください.","ex":"こちらの資料をご覧になりましたか。","exr":"こちらの しりょうを ごらんに なりましたか","ext":"¿Ha visto usted este documento?"},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"拝見する","rd":"はいけんする","when":"Miras tú algo que pertenece o procede de la persona respetada.","ex":"メールを拝見しました。","exr":"メールを はいけん しました","ext":"He leído su correo."}],"note":"拝 significa 'inclinarse con reverencia': aparece también en 拝聴する (escuchar), 拝借する (tomar prestado) y 拝読する (leer).","err":"Usar 拝見する para algo tuyo: 私の写真を拝見してください ✗. Ahí es ご覧ください ✓."},
{"id":"keigo-suru","cat":"keigo","lvl":"N4","title":"する — hacer","sub":"なさる · いたす","intro":"Como する se pega a miles de sustantivos (勉強する, 連絡する…), sus formas keigo se multiplican por todo el idioma: 連絡なさる, 連絡いたします.","rows":[{"tag":"普通形","lbl":"Informal","jp":"する","rd":"する","when":"Con confianza.","ex":"週末は何をする？","exr":"しゅうまつは なにを する？","ext":"¿Qué haces el finde?"},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"します","rd":"します","when":"Cortesía estándar.","ex":"あとで連絡します。","exr":"あとで れんらく します","ext":"Le contacto luego."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"なさる","rd":"なさる","when":"Lo hace la persona respetada.","ex":"どうなさいますか。","exr":"どう なさいますか","ext":"¿Qué desea hacer?"},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"いたす","rd":"いたす","when":"Lo haces tú. 〜いたします es la fórmula estándar de empresa.","ex":"明日、ご連絡いたします。","exr":"あした、ごれんらく いたします","ext":"Le contactaré mañana."}],"note":"よろしくお願いいたします es literalmente 'humildemente le pido su favor': いたす es el motor de la frase más repetida del japonés de negocios.","err":"Confundir なさる (el otro) con いたす (tú). ご確認いたしますか ✗ → ご確認なさいますか ✓."},
{"id":"keigo-shiru","cat":"keigo","lvl":"N3","title":"知る・思う — saber y creer","sub":"ご存じ · 存じる · 存じ上げる","intro":"存じる cubre a la vez 知る y 思う. La distinción fina: 存じ上げる solo para PERSONAS a las que respetas; 存じる para cosas.","rows":[{"tag":"普通形","lbl":"Informal","jp":"知っている／思う","rd":"しっている／おもう","when":"Con confianza.","ex":"その店なら知っている。","exr":"その みせなら しっている","ext":"Esa tienda la conozco."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"知っています／思います","rd":"しっています／おもいます","when":"Cortesía estándar.","ex":"その件は知っています。","exr":"その けんは しっています","ext":"Sé de ese asunto."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"ご存じだ","rd":"ごぞんじだ","when":"Lo sabe la persona respetada.","ex":"この件はご存じですか。","exr":"この けんは ごぞんじですか","ext":"¿Sabe usted de este asunto?"},{"tag":"謙譲語 · cosas","lbl":"Muy formal · TE REBAJA a ti","jp":"存じる／存じております","rd":"ぞんじる／ぞんじております","when":"Sabes o crees tú algo (un dato, un hecho).","ex":"その件は存じております。","exr":"その けんは ぞんじて おります","ext":"Estoy al corriente de ese asunto."},{"tag":"謙譲語 · personas","lbl":"Muy formal · solo personas","jp":"存じ上げる","rd":"ぞんじあげる","when":"Conoces a una persona a la que respetas.","ex":"お名前は存じ上げております。","exr":"おなまえは ぞんじあげて おります","ext":"Conozco su nombre (sé quién es usted)."}],"note":"Para negar que conoces a alguien: 存じ上げません. Para un dato: 存じません. Confundirlos suena a manual mal aprendido.","err":"知りません es correcto pero seco; ante un cliente suena cortante. Usa 存じません／わかりかねます."},
{"id":"keigo-au","cat":"keigo","lvl":"N3","title":"会う — encontrarse con alguien","sub":"お目にかかる, el humilde más elegante","intro":"お目にかかる significa literalmente 'quedar colgado ante los ojos (de usted)': tú te pones ante la mirada del superior. Solo funciona si el respetado es la persona con la que te encuentras.","rows":[{"tag":"普通形","lbl":"Informal","jp":"会う","rd":"あう","when":"Con confianza.","ex":"明日、友達に会う。","exr":"あした、ともだちに あう","ext":"Mañana quedo con un amigo."},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"会います","rd":"あいます","when":"Cortesía estándar.","ex":"明日、お客様に会います。","exr":"あした、おきゃくさまに あいます","ext":"Mañana me reúno con el cliente."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"お会いになる","rd":"おあいになる","when":"Se encuentra la persona respetada (con un tercero).","ex":"社長は誰とお会いになりますか。","exr":"しゃちょうは だれと おあいに なりますか","ext":"¿Con quién se reunirá el presidente?"},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"お目にかかる","rd":"おめにかかる","when":"Te encuentras tú con la persona respetada.","ex":"お目にかかれて光栄です。","exr":"おめに かかれて こうえい です","ext":"Es un honor conocerle."}],"note":"お目にかける es distinto: significa 'mostrarle algo a usted' (=お見せする). No los mezcles.","err":"お目にかかる con un tercero: 田中さんにお目にかかりました, dicho a tu jefe sobre un igual, eleva a quien no toca."},
{"id":"keigo-kiku","cat":"keigo","lvl":"N3","title":"聞く — preguntar y escuchar","sub":"伺う sirve para preguntar, visitar y escuchar","intro":"伺う es un comodín humilde con tres sentidos: preguntar, ir/visitar y oír. El contexto lo desambigua, y por eso es tan frecuente en el trabajo.","rows":[{"tag":"普通形","lbl":"Informal","jp":"聞く","rd":"きく","when":"Con confianza.","ex":"ちょっと聞いてもいい？","exr":"ちょっと きいても いい？","ext":"¿Te puedo preguntar una cosa?"},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"聞きます","rd":"ききます","when":"Cortesía estándar.","ex":"あとで聞きます。","exr":"あとで ききます","ext":"Lo pregunto luego."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"お聞きになる","rd":"おききになる","when":"Pregunta o escucha la persona respetada.","ex":"その話はどこでお聞きになりましたか。","exr":"その はなしは どこで おききに なりましたか","ext":"¿Dónde ha oído usted eso?"},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"伺う／お伺いする","rd":"うかがう／おうかがいする","when":"Preguntas tú a un superior. También 'visitar' y 'oír'.","ex":"一点、伺ってもよろしいでしょうか。","exr":"いってん、うかがっても よろしいでしょうか","ext":"¿Podría hacerle una pregunta?"},{"tag":"謙譲語 · escuchar","lbl":"Muy formal · escuchar con atención","jp":"拝聴する","rd":"はいちょうする","when":"Escuchas una charla o discurso de alguien respetado. Muy formal, casi de ceremonia.","ex":"ご講演を拝聴いたしました。","exr":"ごこうえんを はいちょう いたしました","ext":"Escuché su conferencia."}],"note":"聞く (preguntar/oír), 聴く (escuchar con atención, música) y 訊く (interrogar) se pronuncian きく pero se escriben distinto.","err":"お伺いします es técnicamente doble keigo, pero está tan asentado que se considera correcto. 伺います también vale y es más limpio."},
{"id":"keigo-jugu","cat":"keigo","lvl":"N4","title":"あげる・くれる・もらう — dar y recibir","sub":"La dirección manda: hacia fuera, hacia mí, o yo recibo","intro":"El japonés no tiene un 'dar' neutro: elige el verbo según la dirección del favor. Y cada uno tiene su versión keigo. Es el punto donde más se atasca el estudiante hispanohablante.","rows":[{"tag":"あげる系","lbl":"Yo → otro (hacia fuera)","jp":"あげる → さしあげる／やる","rd":"あげる → さしあげる／やる","when":"Tú das a otro. さしあげる eleva al que recibe; やる es para plantas, animales o inferiores (hoy suena brusco con personas).","ex":"先生にお土産をさしあげました。","exr":"せんせいに おみやげを さしあげました","ext":"Le di un souvenir al profesor."},{"tag":"くれる系","lbl":"Otro → yo (hacia dentro)","jp":"くれる → くださる","rd":"くれる → くださる","when":"Otro te da a TI (o a tu grupo). くださる eleva al que da.","ex":"部長が資料をくださいました。","exr":"ぶちょうが しりょうを くださいました","ext":"El jefe me dio los documentos."},{"tag":"もらう系","lbl":"Yo recibo (desde el otro)","jp":"もらう → いただく","rd":"もらう → いただく","when":"Tú recibes. いただく te rebaja a ti. Mismo hecho que くださる, pero visto desde ti.","ex":"部長に資料をいただきました。","exr":"ぶちょうに しりょうを いただきました","ext":"Recibí los documentos del jefe."}],"note":"部長がくださった y 部長にいただいた describen el MISMO hecho: cambia solo quién es el sujeto de la frase. Ambas son correctas y educadas.","err":"Decir 私は先生にあげました suena a que te pones por encima. Y 〜てあげる ofreciendo ayuda a un superior (持ってあげましょうか) suena condescendiente: usa お持ちしましょうか."},
{"id":"keigo-kariru","cat":"keigo","lvl":"N2","title":"借りる・貸す — pedir y dejar prestado","sub":"拝借する y お貸しする","intro":"Ojo con la dirección: 借りる es TOMAR prestado (viene hacia ti) y 貸す es DEJAR prestado (sale de ti). En español 'prestar' cubre ambos y por eso se confunden tanto.","rows":[{"tag":"普通形","lbl":"Informal","jp":"借りる／貸す","rd":"かりる／かす","when":"Con confianza.","ex":"ペン借りていい？","exr":"ペン かりて いい？","ext":"¿Me dejas un boli?"},{"tag":"丁寧語","lbl":"Formal neutro (-masu)","jp":"借ります／貸します","rd":"かります／かします","when":"Cortesía estándar.","ex":"会議室を借ります。","exr":"かいぎしつを かります","ext":"Voy a usar (tomar prestada) la sala."},{"tag":"尊敬語","lbl":"Muy formal · ELEVA al otro","jp":"お借りになる／お貸しになる","rd":"おかりになる／おかしになる","when":"Toma o deja prestado la persona respetada.","ex":"どちらの車をお借りになりますか。","exr":"どちらの くるまを おかりに なりますか","ext":"¿Qué coche va usted a alquilar?"},{"tag":"謙譲語","lbl":"Muy formal · TE REBAJA a ti","jp":"拝借する／お貸しする","rd":"はいしゃくする／おかしする","when":"拝借する: tomas prestado de un superior. お貸しする: le dejas algo tuyo.","ex":"お電話を拝借できますか。","exr":"おでんわを はいしゃく できますか","ext":"¿Podría usar su teléfono?"}],"note":"拝借 es bastante ceremonioso. En el día a día, お借りしてもよろしいでしょうか es igual de correcto y menos rígido.","err":"Invertir la dirección: querer decir 'te presto mi coche' y soltar 車を借ります (= tomo prestado tu coche)."},
{"id":"keigo-tokushu","cat":"keigo","lvl":"N2","title":"Otros verbos con keigo propio","sub":"着る, 寝る, 死ぬ, くれる… formas que hay que memorizar","intro":"Un puñado de verbos cotidianos tiene forma respetuosa propia que no sigue ningún patrón. Son pocos, pero aparecen constantemente en el trato formal.","rows":[{"tag":"着る → 尊敬語","lbl":"Vestir · ELEVA al otro","jp":"お召しになる","rd":"おめしになる","when":"Se pone ropa la persona respetada. 召す también sirve para 風邪を召す (resfriarse) o お年を召す (envejecer).","ex":"素敵なコートをお召しですね。","exr":"すてきな コートを おめし ですね","ext":"Lleva usted un abrigo precioso."},{"tag":"寝る → 尊敬語","lbl":"Dormir · ELEVA al otro","jp":"お休みになる","rd":"おやすみになる","when":"Duerme o descansa la persona respetada.","ex":"社長はもうお休みになりました。","exr":"しゃちょうは もう おやすみに なりました","ext":"El presidente ya se ha acostado."},{"tag":"死ぬ → 婉曲・尊敬語","lbl":"Morir · eufemismo obligado","jp":"亡くなる／お亡くなりになる","rd":"なくなる／おなくなりになる","when":"死ぬ es brutalmente directo: solo para animales o en contexto médico. Con personas se usa 亡くなる siempre.","ex":"先生は去年お亡くなりになりました。","exr":"せんせいは きょねん おなくなりに なりました","ext":"El profesor falleció el año pasado."},{"tag":"ある → 丁寧語","lbl":"Haber · cortesía elevada","jp":"ございます","rd":"ございます","when":"Versión ultracortés de あります. En tiendas y hoteles es el pan de cada día.","ex":"エレベーターは右手にございます。","exr":"エレベーターは みぎてに ございます","ext":"El ascensor está a su derecha."},{"tag":"です → 丁寧語","lbl":"Ser · cortesía elevada","jp":"でございます","rd":"でございます","when":"Versión ultracortés de です.","ex":"こちらが新商品でございます。","exr":"こちらが しんしょうひん でございます","ext":"Este es el producto nuevo."}],"note":"ございます eleva el tono de TODA la frase, no a una persona concreta: es 丁寧語 puro, no 尊敬語.","err":"Aplicar ございます a personas: 田中がございます ✗. Las personas usan おります → 田中がおります ✓."},
{"id":"keigo-pattern","cat":"keigo","lvl":"N3","title":"El patrón universal: お〜になる / お〜する","sub":"Cuando el verbo no tiene keigo propio","intro":"La mayoría de los verbos NO tiene forma especial. Para ellos existen dos moldes que se construyen sobre la raíz -masu, y basta con no confundir cuál eleva y cuál rebaja.","rows":[{"tag":"お＋ます形＋になる","lbl":"尊敬語 · ELEVA al otro","jp":"お待ちになる／お読みになる","rd":"おまちになる／およみになる","when":"La acción la hace la persona respetada. Regla: quita ます y mete el verbo entre お y になる.","ex":"少々お待ちになってください。","exr":"しょうしょう おまちに なって ください","ext":"Espere un momento, por favor."},{"tag":"お＋ます形＋する","lbl":"謙譲語 · TE REBAJA a ti","jp":"お待ちする／お送りする","rd":"おまちする／おおくりする","when":"La acción la haces TÚ, y afecta a la persona respetada.","ex":"ロビーでお待ちしております。","exr":"ロビーで おまちして おります","ext":"Le espero en el vestíbulo."},{"tag":"ご＋名詞＋になる／する","lbl":"Con verbos de origen chino","jp":"ご利用になる／ご連絡する","rd":"ごりようになる／ごれんらくする","when":"Los verbos 〜する de raíz china (漢語) usan ご en vez de お.","ex":"ご利用になれます。／のちほどご連絡いたします。","exr":"ごりように なれます／のちほど ごれんらく いたします","ext":"Puede usarlo. / Le contactaré más tarde."},{"tag":"〜れる／られる","lbl":"尊敬語 ligero","jp":"読まれる／来られる","rd":"よまれる／こられる","when":"Respeto suave, muy usado entre compañeros de oficina. Ambiguo con pasiva y potencial, pero cómodo.","ex":"部長はもう帰られました。","exr":"ぶちょうは もう かえられました","ext":"El jefe ya se ha ido."}],"note":"Verbos de una sola sílaba en la raíz (見る→見, いる→い) NO admiten el patrón: お見になる ✗. Esos son justo los que tienen forma propia (ご覧になる).","err":"La confusión clásica: お待ちしてください ✗. Si le pides a ÉL que espere, él es el sujeto → お待ちになってください / お待ちください ✓."},
{"id":"keigo-nijuu","cat":"keigo","lvl":"N1","title":"二重敬語 — el exceso de keigo","sub":"Cuándo pasarse es un error… y cuándo no","intro":"Apilar dos marcas de respeto sobre el mismo verbo se llama 二重敬語 y se considera incorrecto. La trampa: unas cuantas formas dobles están tan asentadas que hoy son estándar.","rows":[{"tag":"✗ 二重敬語","lbl":"Incorrecto","jp":"おっしゃられる","rd":"おっしゃられる","when":"おっしゃる ya es 尊敬語; añadir られる lo duplica. Correcto: おっしゃる.","ex":"先生がおっしゃいました。","exr":"せんせいが おっしゃいました","ext":"El profesor dijo. (forma correcta)"},{"tag":"✗ 二重敬語","lbl":"Incorrecto","jp":"お召し上がりになられる","rd":"おめしあがりになられる","when":"Tres capas de respeto sobre 食べる. Correcto: 召し上がる.","ex":"どうぞ召し上がってください。","exr":"どうぞ めしあがって ください","ext":"Sírvase, por favor. (forma correcta)"},{"tag":"✓ 慣用","lbl":"Doble pero aceptado","jp":"お伺いする","rd":"おうかがいする","when":"伺う ya es humilde, pero お伺いします está tan extendido que la propia guía oficial del keigo lo admite.","ex":"明日お伺いします。","exr":"あした おうかがい します","ext":"Iré mañana a verle."},{"tag":"✓ 慣用","lbl":"Doble pero aceptado","jp":"お召し上がりください","rd":"おめしあがりください","when":"Igual: técnicamente redundante, en la práctica es la fórmula normal en restaurantes y envases.","ex":"温めてお召し上がりください。","exr":"あたためて おめしあがり ください","ext":"Caliéntelo antes de consumir."}],"note":"敬語連結 (encadenar keigo con て: 読んでいらっしゃる) NO es 二重敬語 y es perfectamente correcto: cada verbo lleva una sola marca.","err":"Pasarse de keigo no suena más educado: suena inseguro o irónico. Ante la duda, una sola marca bien puesta gana siempre."},
{"id":"jita-intro","cat":"jita","lvl":"N4","title":"自動詞・他動詞 — la idea central","sub":"が pasa solo · を lo hago yo","intro":"El japonés tiene parejas de verbos casi idénticos que se diferencian en una sola cosa: si la acción OCURRE por sí sola (自動詞, con が) o si ALGUIEN la provoca (他動詞, con を). El español no distingue así, y por eso esta es una de las mayores fuentes de error.","rows":[{"tag":"自動詞","lbl":"Intransitivo · ocurre solo","jp":"〜が + 自動詞","rd":"","when":"Describe lo que pasa, sin señalar culpable. El foco está en el resultado o el estado.","ex":"ドアが開いた。","exr":"ドアが あいた","ext":"La puerta se abrió."},{"tag":"他動詞","lbl":"Transitivo · alguien lo hace","jp":"〜を + 他動詞","rd":"","when":"Alguien ejecuta la acción sobre algo. El foco está en quien actúa.","ex":"私がドアを開けた。","exr":"わたしが ドアを あけた","ext":"Yo abrí la puerta."},{"tag":"〜ている","lbl":"Estado resultante","jp":"自動詞 + ている","rd":"","when":"Con intransitivo, ている describe el ESTADO en que quedó algo.","ex":"ドアが開いている。","exr":"ドアが あいている","ext":"La puerta está abierta."},{"tag":"〜てある","lbl":"Estado dejado a propósito","jp":"他動詞 + てある","rd":"","when":"Con transitivo, てある indica que alguien lo dejó así con una intención.","ex":"ドアが開けてある。","exr":"ドアが あけてある","ext":"La puerta está abierta (alguien la dejó así a propósito)."}],"note":"Truco útil: la mayoría de intransitivos acaba en -aru y su transitivo en -eru (閉まる/閉める, 始まる/始める). No es una regla universal, pero cubre muchísimos pares.","err":"Traducir literalmente del español. 'Abrí la puerta' es ドアを開けた, pero 'la puerta se abrió' NO es ドアを開いた: es ドアが開いた."},
{"id":"jita-aku","cat":"jita","lvl":"N4","title":"開く・開ける — abrir","sub":"あく (solo) · あける (yo)","intro":"El par más citado. Ojo con la lectura: 開く se lee あく como intransitivo, pero ひらく es otro verbo distinto que puede ser ambas cosas.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"開く","rd":"あく","when":"Algo se abre por sí solo o ya está abierto.","ex":"風でドアが開いた。","exr":"かぜで ドアが あいた","ext":"La puerta se abrió con el viento."},{"tag":"他動詞","lbl":"Transitivo","jp":"開ける","rd":"あける","when":"Alguien abre algo.","ex":"窓を開けてもいいですか。","exr":"まどを あけても いいですか","ext":"¿Puedo abrir la ventana?"},{"tag":"両方","lbl":"Verbo aparte","jp":"開く","rd":"ひらく","when":"ひらく sirve para ambos: abrir(se) algo que se despliega (libro, flor, reunión, tienda).","ex":"教科書を開いてください。／花が開いた。","exr":"きょうかしょを ひらいて ください／はなが ひらいた","ext":"Abrid el libro. / La flor se abrió."}],"note":"店が開く (あく) = está abierto al público hoy. 店を開く (ひらく) = fundar/inaugurar un negocio.","err":"Decir ドアを開いた queriendo decir 'abrí la puerta'. Lo natural es ドアを開けた."},
{"id":"jita-shimaru","cat":"jita","lvl":"N4","title":"閉まる・閉める — cerrar","sub":"しまる (solo) · しめる (yo)","intro":"Pareja simétrica de 開く/開ける. Aquí el patrón -aru/-eru se ve perfectamente.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"閉まる","rd":"しまる","when":"Algo se cierra o está cerrado.","ex":"店は八時に閉まります。","exr":"みせは はちじに しまります","ext":"La tienda cierra a las ocho."},{"tag":"他動詞","lbl":"Transitivo","jp":"閉める","rd":"しめる","when":"Alguien cierra algo.","ex":"寒いので窓を閉めました。","exr":"さむいので まどを しめました","ext":"Como hacía frío, cerré la ventana."},{"tag":"関連","lbl":"No confundir","jp":"閉じる","rd":"とじる","when":"Cerrar algo que se pliega (libro, ojos, paraguas). Sirve como transitivo e intransitivo.","ex":"目を閉じてください。","exr":"めを とじて ください","ext":"Cierre los ojos, por favor."}],"note":"閉まっている = está cerrado (estado). 閉めてある = alguien lo cerró y lo dejó así a propósito.","err":"店が閉めています ✗. La tienda no cierra a nadie: 店は閉まっています ✓."},
{"id":"jita-hajimaru","cat":"jita","lvl":"N4","title":"始まる・始める — empezar","sub":"はじまる (empieza) · はじめる (lo empiezo)","intro":"En español decimos 'la clase empieza' y 'empiezo la clase' con el mismo verbo. En japonés son dos palabras distintas y confundirlas es error de examen garantizado.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"始まる","rd":"はじまる","when":"Algo empieza (un evento, una clase, una película).","ex":"授業は九時に始まります。","exr":"じゅぎょうは くじに はじまります","ext":"La clase empieza a las nueve."},{"tag":"他動詞","lbl":"Transitivo","jp":"始める","rd":"はじめる","when":"Alguien empieza algo.","ex":"来月から日本語の勉強を始めます。","exr":"らいげつから にほんごの べんきょうを はじめます","ext":"Empezaré a estudiar japonés el mes que viene."}],"note":"Como sufijo se usa siempre el transitivo: 読み始める (empezar a leer), 降り始める (empezar a llover) — aunque el verbo base sea intransitivo.","err":"授業を始まります ✗ → 授業が始まります ✓ (la clase empieza) / 授業を始めます ✓ (yo empiezo la clase)."},
{"id":"jita-owaru","cat":"jita","lvl":"N4","title":"終わる・終える — terminar","sub":"El caso raro: 終わる vale para las dos cosas","intro":"Aquí hay una excepción interesante: 終わる es intransitivo, pero en la práctica también se usa como transitivo. 終える es puramente transitivo y suena más formal.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"終わる","rd":"おわる","when":"Algo termina.","ex":"映画はもう終わりました。","exr":"えいがは もう おわりました","ext":"La película ya ha terminado."},{"tag":"他動詞","lbl":"Transitivo (formal)","jp":"終える","rd":"おえる","when":"Alguien termina algo. Registro escrito o formal.","ex":"無事に仕事を終えました。","exr":"ぶじに しごとを おえました","ext":"Terminé el trabajo sin problemas."},{"tag":"例外","lbl":"終わる como transitivo","jp":"〜を終わる","rd":"〜を おわる","when":"Muy usado en el habla: 宿題を終わる es aceptable, aunque 終える o 終わらせる son más correctos.","ex":"宿題を終わらせてから遊ぶ。","exr":"しゅくだいを おわらせてから あそぶ","ext":"Juego después de terminar los deberes."}],"note":"Como sufijo, siempre 終わる: 読み終わる (terminar de leer), 食べ終わる (terminar de comer).","err":"Usar 終える en conversación casual suena libresco. En el día a día: 終わらせる o 終わる."},
{"id":"jita-hairu","cat":"jita","lvl":"N4","title":"入る・入れる — entrar y meter","sub":"はいる (entra) · いれる (lo meto)","intro":"入る tiene una lectura traicionera: como intransitivo es はいる, pero el mismo kanji aparece en 入れる (いれる) y en compuestos como 入学 (にゅうがく).","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"入る","rd":"はいる","when":"Algo o alguien entra.","ex":"部屋に猫が入ってきた。","exr":"へやに ねこが はいって きた","ext":"Un gato entró en la habitación."},{"tag":"他動詞","lbl":"Transitivo","jp":"入れる","rd":"いれる","when":"Alguien mete algo. También 'preparar' café o té.","ex":"かばんに本を入れます。／コーヒーを入れましょうか。","exr":"かばんに ほんを いれます／コーヒーを いれましょうか","ext":"Meto el libro en la bolsa. / ¿Preparo café?"}],"note":"気に入る (きにいる, gustar) es intransitivo pese a la apariencia: この服が気に入った (me gustó esta ropa).","err":"お風呂を入る ✗ → お風呂に入る ✓ (bañarse). Y スイッチを入れる ✓ = encender el interruptor."},
{"id":"jita-deru","cat":"jita","lvl":"N4","title":"出る・出す — salir y sacar","sub":"でる (sale) · だす (lo saco)","intro":"Una de las parejas más productivas del idioma: 出す aparece además como sufijo con el sentido de 'empezar de golpe'.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"出る","rd":"でる","when":"Algo o alguien sale, aparece o asiste.","ex":"七時に家を出ます。／会議に出ます。","exr":"しちじに いえを でます／かいぎに でます","ext":"Salgo de casa a las siete. / Asisto a la reunión."},{"tag":"他動詞","lbl":"Transitivo","jp":"出す","rd":"だす","when":"Alguien saca, envía o entrega algo.","ex":"手紙を出しました。／宿題を出してください。","exr":"てがみを だしました／しゅくだいを だして ください","ext":"Envié la carta. / Entregad los deberes."},{"tag":"接尾辞","lbl":"Como sufijo","jp":"〜出す","rd":"〜だす","when":"Pegado a la raíz -masu significa 'empezar de repente'.","ex":"急に雨が降り出した。","exr":"きゅうに あめが ふりだした","ext":"De pronto empezó a llover."}],"note":"Atención: 家を出る lleva を pero es intransitivo. Ese を marca el punto de salida (como en 電車を降りる), no un objeto directo.","err":"Confundir 〜出す (empezar de golpe, no controlado) con 〜始める (empezar, neutro). 泣き出す = romper a llorar; 泣き始める suena raro."},
{"id":"jita-agaru","cat":"jita","lvl":"N4","title":"上がる・上げる — subir","sub":"あがる (sube) · あげる (lo subo)","intro":"Además del sentido físico, este par cubre precios, temperaturas y niveles. Y 上げる es el mismo verbo que 'dar' (あげる), lo que despista al principio.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"上がる","rd":"あがる","when":"Algo sube por sí solo.","ex":"来月から電気代が上がります。","exr":"らいげつから でんきだいが あがります","ext":"La factura de la luz sube el mes que viene."},{"tag":"他動詞","lbl":"Transitivo","jp":"上げる","rd":"あげる","when":"Alguien sube algo.","ex":"手を上げてください。／値段を上げた。","exr":"てを あげて ください／ねだんを あげた","ext":"Levantad la mano. / Subieron el precio."},{"tag":"関連","lbl":"No confundir","jp":"登る／昇る","rd":"のぼる","when":"登る: escalar con esfuerzo (montaña, escalera). 昇る: ascender majestuosamente (sol, humo).","ex":"山に登る。／日が昇る。","exr":"やまに のぼる／ひが のぼる","ext":"Subir la montaña. / Sale el sol."}],"note":"上がる también significa 'entrar en una casa japonesa' (どうぞお上がりください), porque el suelo está elevado respecto al genkan.","err":"Decir 値段が上げました ✗. El precio no sube nada a nadie: 値段が上がりました ✓."},
{"id":"jita-sagaru","cat":"jita","lvl":"N4","title":"下がる・下げる — bajar","sub":"さがる (baja) · さげる (lo bajo)","intro":"Simétrico de 上がる/上げる. Cubre también el sentido de 'retirar' algo de la mesa, muy usado en restaurantes.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"下がる","rd":"さがる","when":"Algo baja por sí solo.","ex":"熱が下がりました。","exr":"ねつが さがりました","ext":"Me ha bajado la fiebre."},{"tag":"他動詞","lbl":"Transitivo","jp":"下げる","rd":"さげる","when":"Alguien baja o retira algo.","ex":"音量を下げてください。／お皿をお下げします。","exr":"おんりょうを さげて ください／おさらを おさげ します","ext":"Baja el volumen. / Le retiro el plato."},{"tag":"関連","lbl":"No confundir","jp":"降りる／降ろす","rd":"おりる／おろす","when":"Bajar DE un vehículo o lugar alto. 降ろす: bajar algo/a alguien, o sacar dinero del banco.","ex":"次の駅で降ります。／お金を降ろす。","exr":"つぎの えきで おります／おかねを おろす","ext":"Bajo en la próxima estación. / Sacar dinero."}],"note":"お皿をお下げしてもよろしいですか es la frase exacta del camarero al retirar platos: 下げる + keigo humilde.","err":"熱を下がりました ✗ → 熱が下がりました ✓."},
{"id":"jita-kimaru","cat":"jita","lvl":"N4","title":"決まる・決める — decidir","sub":"きまる (queda decidido) · きめる (lo decido)","intro":"Muy útil en el trabajo: 決まる te permite comunicar una decisión SIN decir quién la tomó, algo que el japonés hace constantemente por cortesía.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"決まる","rd":"きまる","when":"Algo queda decidido (sin señalar por quién).","ex":"会議の日程が決まりました。","exr":"かいぎの にっていが きまりました","ext":"Se ha decidido la fecha de la reunión."},{"tag":"他動詞","lbl":"Transitivo","jp":"決める","rd":"きめる","when":"Alguien decide algo.","ex":"自分で決めます。","exr":"じぶんで きめます","ext":"Lo decido yo mismo."}],"note":"〜に決まっている es una expresión hecha: significa 'seguro que es así, no puede ser de otra forma'. 嘘に決まっている = es mentira, seguro.","err":"En japonés de empresa, decir 私が決めました suena a echarse flores. Lo natural es 決まりました, aunque lo decidieras tú."},
{"id":"jita-kawaru","cat":"jita","lvl":"N4","title":"変わる・変える — cambiar","sub":"かわる (cambia) · かえる (lo cambio)","intro":"Cuidado con la lectura: 変える (かえる) suena igual que 帰る (volver) y 買える (poder comprar). El contexto y el kanji los distinguen.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"変わる","rd":"かわる","when":"Algo cambia por sí solo.","ex":"信号が青に変わった。","exr":"しんごうが あおに かわった","ext":"El semáforo se puso en verde."},{"tag":"他動詞","lbl":"Transitivo","jp":"変える","rd":"かえる","when":"Alguien cambia algo.","ex":"予定を変えてもいいですか。","exr":"よていを かえても いいですか","ext":"¿Puedo cambiar los planes?"},{"tag":"関連","lbl":"No confundir","jp":"替える／換える","rd":"かえる","when":"替える: sustituir por otro igual (pilas, ropa). 換える: intercambiar (dinero, aire).","ex":"電池を替える。／円をユーロに換える。","exr":"でんちを かえる／えんを ユーロに かえる","ext":"Cambiar las pilas. / Cambiar yenes a euros."}],"note":"変わっている significa además 'ser raro/excéntrico': あの人は変わっている = esa persona es peculiar.","err":"予定が変えました ✗ → 予定が変わりました ✓ (los planes cambiaron) / 予定を変えました ✓ (cambié los planes)."},
{"id":"jita-atsumaru","cat":"jita","lvl":"N4","title":"集まる・集める — reunir","sub":"あつまる (se reúnen) · あつめる (los reúno)","intro":"Par regular -aru/-eru. Sirve tanto para personas que se juntan como para colecciones de objetos.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"集まる","rd":"あつまる","when":"Varias cosas o personas se juntan.","ex":"八時に駅前に集まってください。","exr":"はちじに えきまえに あつまって ください","ext":"Reuníos delante de la estación a las ocho."},{"tag":"他動詞","lbl":"Transitivo","jp":"集める","rd":"あつめる","when":"Alguien junta o colecciona cosas.","ex":"切手を集めるのが趣味です。","exr":"きってを あつめるのが しゅみです","ext":"Mi hobby es coleccionar sellos."}],"note":"注目を集める (atraer la atención) y 人気を集める (ganar popularidad) son colocaciones muy frecuentes en prensa.","err":"人を集まる ✗ → 人を集める ✓ (reunir gente) / 人が集まる ✓ (la gente se reúne)."},
{"id":"jita-tsuzuku","cat":"jita","lvl":"N4","title":"続く・続ける — continuar","sub":"つづく (sigue) · つづける (lo sigo)","intro":"Otro par que en español se dice igual ('el partido continúa' / 'continúo el partido') y en japonés obliga a elegir.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"続く","rd":"つづく","when":"Algo continúa por sí solo.","ex":"雨が三日も続いている。","exr":"あめが みっかも つづいている","ext":"Lleva tres días lloviendo sin parar."},{"tag":"他動詞","lbl":"Transitivo","jp":"続ける","rd":"つづける","when":"Alguien continúa algo.","ex":"毎日日本語の勉強を続けています。","exr":"まいにち にほんごの べんきょうを つづけています","ext":"Sigo estudiando japonés todos los días."},{"tag":"接尾辞","lbl":"Como sufijo","jp":"〜続ける","rd":"〜つづける","when":"Pegado a la raíz -masu: seguir haciendo algo.","ex":"三時間歩き続けた。","exr":"さんじかん あるきつづけた","ext":"Estuve andando tres horas seguidas."}],"note":"Al final de un capítulo verás 続く solo: significa 'continuará'.","err":"勉強が続けています ✗ → 勉強を続けています ✓."},
{"id":"jita-tomaru","cat":"jita","lvl":"N4","title":"止まる・止める — parar","sub":"とまる (se para) · とめる (lo paro)","intro":"Ojo doble: 止まる también se lee とまる con el sentido de 'alojarse' cuando se escribe 泊まる, y やめる (辞める/止める) es otro verbo distinto.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"止まる","rd":"とまる","when":"Algo se para solo.","ex":"エレベーターが止まった。","exr":"エレベーターが とまった","ext":"El ascensor se paró."},{"tag":"他動詞","lbl":"Transitivo","jp":"止める","rd":"とめる","when":"Alguien para algo. También aparcar.","ex":"ここに車を止めないでください。","exr":"ここに くるまを とめないで ください","ext":"No aparque el coche aquí."},{"tag":"関連","lbl":"No confundir","jp":"やめる","rd":"やめる","when":"Dejar de hacer algo, abandonar una costumbre o un trabajo (辞める).","ex":"タバコをやめました。／会社を辞めます。","exr":"タバコを やめました／かいしゃを やめます","ext":"Dejé de fumar. / Dejo la empresa."},{"tag":"同音","lbl":"Homófono","jp":"泊まる","rd":"とまる","when":"Alojarse, pasar la noche.","ex":"ホテルに泊まります。","exr":"ホテルに とまります","ext":"Me alojo en un hotel."}],"note":"止める tiene dos lecturas: とめる (parar algo físico) y やめる (dejar una actividad). El kanji es el mismo; manda el contexto.","err":"時計が止めました ✗ → 時計が止まりました ✓ (el reloj se paró)."},
{"id":"jita-tsuku","cat":"jita","lvl":"N4","title":"付く・付ける — pegar y encender","sub":"つく (se pone) · つける (lo pongo)","intro":"Este par cubre desde encender la luz hasta que algo venga incluido. Es de los más frecuentes del día a día.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"付く","rd":"つく","when":"Algo se enciende, se pega o viene incluido.","ex":"電気が付いている。／このセットにはドリンクが付きます。","exr":"でんきが ついている／このセットには ドリンクが つきます","ext":"La luz está encendida. / Este menú incluye bebida."},{"tag":"他動詞","lbl":"Transitivo","jp":"付ける","rd":"つける","when":"Alguien enciende o coloca algo.","ex":"エアコンを付けてもいいですか。／名前を付ける。","exr":"エアコンを つけても いいですか／なまえを つける","ext":"¿Puedo encender el aire? / Poner un nombre."},{"tag":"同音","lbl":"Homófono","jp":"着く","rd":"つく","when":"Llegar a un sitio.","ex":"東京駅に着きました。","exr":"とうきょうえきに つきました","ext":"He llegado a la estación de Tokio."}],"note":"気を付ける (tener cuidado) es transitivo y lleva を: 車に気を付けて (cuidado con los coches).","err":"電気を付いている ✗ → 電気が付いている ✓ (la luz está encendida) / 電気を付けている ✓ (tengo la luz encendida)."},
{"id":"jita-kieru","cat":"jita","lvl":"N4","title":"消える・消す — apagar y desaparecer","sub":"きえる (desaparece) · けす (lo apago)","intro":"Par irregular: no sigue el patrón -aru/-eru. Hay que memorizarlo tal cual.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"消える","rd":"きえる","when":"Algo se apaga o desaparece.","ex":"急に電気が消えた。","exr":"きゅうに でんきが きえた","ext":"De pronto se apagó la luz."},{"tag":"他動詞","lbl":"Transitivo","jp":"消す","rd":"けす","when":"Alguien apaga o borra algo.","ex":"寝る前にテレビを消してください。","exr":"ねる まえに テレビを けして ください","ext":"Apaga la tele antes de dormir."}],"note":"消しゴム (goma de borrar) viene de 消す: literalmente 'goma de borrar'.","err":"火が消しました ✗ → 火が消えました ✓ (el fuego se apagó)."},
{"id":"jita-okiru","cat":"jita","lvl":"N4","title":"起きる・起こす — levantar(se) y ocurrir","sub":"おきる (se levanta / ocurre) · おこす (lo levanto / lo provoco)","intro":"Doble sentido: además de levantarse de la cama, este par expresa que un suceso ocurre o alguien lo provoca.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"起きる","rd":"おきる","when":"Levantarse, o que ocurra un suceso.","ex":"毎朝六時に起きます。／事故が起きた。","exr":"まいあさ ろくじに おきます／じこが おきた","ext":"Me levanto a las seis. / Ocurrió un accidente."},{"tag":"他動詞","lbl":"Transitivo","jp":"起こす","rd":"おこす","when":"Despertar a alguien, o provocar un suceso.","ex":"七時に起こしてください。／問題を起こす。","exr":"しちじに おこして ください／もんだいを おこす","ext":"Despiértame a las siete. / Causar problemas."}],"note":"起こる (おこる) es otro intransitivo que solo significa 'ocurrir': 地震が起こる. Y 怒る (おこる) es 'enfadarse': mismo sonido, kanji distinto.","err":"事故を起きた ✗ → 事故が起きた ✓ (ocurrió un accidente) / 事故を起こした ✓ (provocó un accidente)."},
{"id":"jita-naoru","cat":"jita","lvl":"N3","title":"直る・直す vs 治る・治す — arreglar y curar","sub":"Mismo sonido, dos kanji, dos mundos","intro":"Cuatro verbos que suenan igual: なおる/なおす. El kanji decide si hablas de objetos (直) o de salud (治), y la vocal decide si pasa solo o lo haces tú.","rows":[{"tag":"自動詞 · 直","lbl":"Objetos · se arregla","jp":"直る","rd":"なおる","when":"Algo se arregla o queda arreglado.","ex":"パソコンが直りました。","exr":"パソコンが なおりました","ext":"El ordenador ya funciona."},{"tag":"他動詞 · 直","lbl":"Objetos · lo arreglo","jp":"直す","rd":"なおす","when":"Alguien arregla o corrige algo.","ex":"間違いを直してください。","exr":"まちがいを なおして ください","ext":"Corrige los errores."},{"tag":"自動詞 · 治","lbl":"Salud · se cura","jp":"治る","rd":"なおる","when":"Una enfermedad o herida se cura.","ex":"風邪が治りました。","exr":"かぜが なおりました","ext":"Se me ha curado el resfriado."},{"tag":"他動詞 · 治","lbl":"Salud · lo curo","jp":"治す","rd":"なおす","when":"Alguien cura una enfermedad.","ex":"早く風邪を治してください。","exr":"はやく かぜを なおして ください","ext":"Cúrate pronto del resfriado."}],"note":"Como sufijo, 〜直す (なおす) significa 'volver a hacer': やり直す (rehacer), read直す→読み直す (releer).","err":"風邪が治しました ✗ → 風邪が治りました ✓. Y escribir 風邪を直す (con 直) es error de kanji: las enfermedades usan 治."},
{"id":"jita-fueru","cat":"jita","lvl":"N3","title":"増える・増やす / 減る・減らす — aumentar y reducir","sub":"Los pares de cantidad","intro":"Fundamentales para hablar de datos, dinero y estadísticas. Muy frecuentes en el 読解 del JLPT.","rows":[{"tag":"自動詞","lbl":"Aumenta solo","jp":"増える","rd":"ふえる","when":"Algo aumenta.","ex":"外国人の観光客が増えています。","exr":"がいこくじんの かんこうきゃくが ふえています","ext":"Están aumentando los turistas extranjeros."},{"tag":"他動詞","lbl":"Lo aumento","jp":"増やす","rd":"ふやす","when":"Alguien aumenta algo.","ex":"貯金を増やしたい。","exr":"ちょきんを ふやしたい","ext":"Quiero aumentar mis ahorros."},{"tag":"自動詞","lbl":"Disminuye solo","jp":"減る","rd":"へる","when":"Algo disminuye.","ex":"人口が減っている。／お腹が減った。","exr":"じんこうが へっている／おなかが へった","ext":"La población está disminuyendo. / Tengo hambre."},{"tag":"他動詞","lbl":"Lo reduzco","jp":"減らす","rd":"へらす","when":"Alguien reduce algo.","ex":"体重を減らします。","exr":"たいじゅうを へらします","ext":"Voy a bajar de peso."}],"note":"お腹が減った (tengo hambre) usa el intransitivo: literalmente 'se me ha reducido el estómago'.","err":"人口を減っている ✗ → 人口が減っている ✓."},
{"id":"jita-ochiru","cat":"jita","lvl":"N3","title":"落ちる・落とす — caer y dejar caer","sub":"おちる (cae) · おとす (lo tiro)","intro":"Además del sentido físico, cubre suspender un examen (落ちる) y perder un objeto (落とす).","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"落ちる","rd":"おちる","when":"Algo cae. También: suspender un examen.","ex":"財布が落ちましたよ。／試験に落ちた。","exr":"さいふが おちましたよ／しけんに おちた","ext":"Se le ha caído la cartera. / Suspendí el examen."},{"tag":"他動詞","lbl":"Transitivo","jp":"落とす","rd":"おとす","when":"Alguien deja caer o pierde algo. También: bajar velocidad, quitar una mancha.","ex":"どこかで鍵を落としました。／スピードを落とす。","exr":"どこかで かぎを おとしました／スピードを おとす","ext":"He perdido las llaves. / Reducir la velocidad."}],"note":"落とし物 (objeto perdido) viene de 落とす. En una estación verás 落とし物センター: oficina de objetos perdidos.","err":"財布を落ちました ✗ → 財布を落としました ✓ (se me cayó/perdí la cartera)."},
{"id":"jita-mitsukaru","cat":"jita","lvl":"N3","title":"見つかる・見つける — encontrar","sub":"みつかる (aparece) · みつける (lo encuentro)","intro":"El intransitivo se usa muchísimo: en japonés lo natural es decir 'apareció' en vez de 'lo encontré'.","rows":[{"tag":"自動詞","lbl":"Intransitivo","jp":"見つかる","rd":"みつかる","when":"Algo aparece o es encontrado (sin decir por quién).","ex":"なくした鍵が見つかりました。","exr":"なくした かぎが みつかりました","ext":"Han aparecido las llaves que perdí."},{"tag":"他動詞","lbl":"Transitivo","jp":"見つける","rd":"みつける","when":"Alguien encuentra algo activamente.","ex":"いい店を見つけました。","exr":"いい みせを みつけました","ext":"He encontrado un buen sitio."}],"note":"見つかる también significa 'ser descubierto/pillado': 親に見つかった = me pillaron mis padres.","err":"仕事が見つけました ✗ → 仕事が見つかりました ✓ (encontré trabajo, apareció) / 仕事を見つけました ✓ (lo busqué y lo encontré)."},
{"id":"jita-nokoru","cat":"jita","lvl":"N3","title":"残る・残す / 届く・届ける — quedar y llegar","sub":"Dos pares muy útiles del día a día","intro":"Dos parejas regulares más, de uso constante: lo que sobra y lo que llega.","rows":[{"tag":"自動詞","lbl":"Queda solo","jp":"残る","rd":"のこる","when":"Algo queda o sobra.","ex":"ご飯がまだ残っている。","exr":"ごはんが まだ のこっている","ext":"Todavía queda comida."},{"tag":"他動詞","lbl":"Lo dejo","jp":"残す","rd":"のこす","when":"Alguien deja algo sin consumir o para más tarde.","ex":"野菜を残さないでください。","exr":"やさいを のこさないで ください","ext":"No dejes las verduras."},{"tag":"自動詞","lbl":"Llega solo","jp":"届く","rd":"とどく","when":"Algo llega (un paquete, una carta). También: alcanzar con la mano.","ex":"荷物が届きました。／棚に手が届かない。","exr":"にもつが とどきました","ext":"Ha llegado el paquete. / No alcanzo al estante."},{"tag":"他動詞","lbl":"Lo entrego","jp":"届ける","rd":"とどける","when":"Alguien entrega o hace llegar algo.","ex":"忘れ物を交番に届けました。","exr":"わすれものを こうばんに とどけました","ext":"Llevé el objeto perdido a la comisaría."}],"note":"手が届く (alcanzar con la mano) se usa también en sentido figurado: 手の届く値段 = un precio asequible.","err":"荷物を届きました ✗ → 荷物が届きました ✓ (llegó el paquete)."},
{"id":"tsukai-iu","cat":"tsukaiwake","lvl":"N3","title":"言う・話す・しゃべる・述べる","sub":"Cuatro formas de decir algo","intro":"Todos se traducen por 'decir' o 'hablar', pero cambian el foco: el CONTENIDO de lo dicho, el ACTO de conversar, la charla informal o la exposición formal.","rows":[{"tag":"言う","lbl":"El contenido","jp":"言う","rd":"いう","when":"Foco en QUÉ se dice. Se usa con と para citar. No conversa: solo emite.","ex":"彼は「行かない」と言った。","exr":"かれは「いかない」と いった","ext":"Él dijo «no voy»."},{"tag":"話す","lbl":"El acto de conversar","jp":"話す","rd":"はなす","when":"Foco en la ACCIÓN de hablar con alguien, o dominar un idioma.","ex":"友達と将来について話しました。／日本語を話せます。","exr":"ともだちと しょうらいに ついて はなしました","ext":"Hablé con un amigo sobre el futuro. / Sé hablar japonés."},{"tag":"しゃべる","lbl":"Coloquial · charlar","jp":"しゃべる","rd":"しゃべる","when":"Charlar sin más, cotorrear. Informal; puede tener matiz negativo (hablar de más).","ex":"授業中にしゃべらないで。","exr":"じゅぎょうちゅうに しゃべらないで","ext":"No cotorrees en clase."},{"tag":"述べる","lbl":"Formal · exponer","jp":"述べる","rd":"のべる","when":"Exponer una opinión o hecho de forma formal, sobre todo por escrito.","ex":"意見を述べさせていただきます。","exr":"いけんを のべさせて いただきます","ext":"Permítame exponer mi opinión."}],"note":"「〜と言う」 es obligatorio para citar. 話す no admite cita directa: 「行かない」と話した suena raro.","err":"日本語を言えます ✗ → 日本語を話せます ✓. Los idiomas se 話す, no se 言う."},
{"id":"tsukai-miru","cat":"tsukaiwake","lvl":"N3","title":"見る・見える・見られる・観る・眺める","sub":"Ver, verse y poder ver","intro":"La diferencia clave está entre 見える (entra en tu campo visual sin querer) y 見られる (tienes la posibilidad de verlo). Confundirlos es error clásico de examen.","rows":[{"tag":"見る","lbl":"Mirar activamente","jp":"見る","rd":"みる","when":"Diriges la vista voluntariamente.","ex":"テレビを見ます。","exr":"テレビを みます","ext":"Veo la tele."},{"tag":"見える","lbl":"Se ve · involuntario","jp":"見える","rd":"みえる","when":"Algo entra en tu vista sin que lo busques. Es una CAPACIDAD natural o una condición del entorno. Lleva が.","ex":"ここから富士山が見えます。","exr":"ここから ふじさんが みえます","ext":"Desde aquí se ve el monte Fuji."},{"tag":"見られる","lbl":"Se puede ver · posibilidad","jp":"見られる","rd":"みられる","when":"Existe la OPORTUNIDAD o el permiso de verlo. Depende de circunstancias, no de tus ojos.","ex":"この映画はネットで見られます。","exr":"この えいがは ネットで みられます","ext":"Esta película se puede ver por internet."},{"tag":"観る","lbl":"Contemplar un espectáculo","jp":"観る","rd":"みる","when":"Mismo sonido que 見る, pero para espectáculos: cine, teatro, deporte.","ex":"映画館で映画を観た。","exr":"えいがかんで えいがを みた","ext":"Vi una película en el cine."},{"tag":"眺める","lbl":"Contemplar largamente","jp":"眺める","rd":"ながめる","when":"Mirar algo amplio y lejano, sin prisa: un paisaje, el mar.","ex":"窓から海を眺めていた。","exr":"まどから うみを ながめていた","ext":"Contemplaba el mar desde la ventana."}],"note":"Misma lógica en 聞こえる (se oye, sin querer) vs 聞ける (se puede escuchar, hay oportunidad).","err":"星が見られます dicho de una noche despejada suena raro: si es por tus ojos y el entorno, es 星が見えます."},
{"id":"tsukai-kiku","cat":"tsukaiwake","lvl":"N3","title":"聞く・聞こえる・聴く・訊く","sub":"Oír, escuchar y preguntar","intro":"Los cuatro se pronuncian きく. El kanji marca la intención: oír de pasada, escuchar con atención o interrogar.","rows":[{"tag":"聞く","lbl":"Oír / preguntar","jp":"聞く","rd":"きく","when":"Oír algo, o preguntar. Es el genérico y el más frecuente.","ex":"音楽を聞きます。／道を聞きました。","exr":"おんがくを ききます／みちを ききました","ext":"Escucho música. / Pregunté el camino."},{"tag":"聞こえる","lbl":"Se oye · involuntario","jp":"聞こえる","rd":"きこえる","when":"Un sonido llega a tus oídos sin que lo busques. Lleva が.","ex":"隣の部屋から声が聞こえる。","exr":"となりの へやから こえが きこえる","ext":"Se oyen voces de la habitación de al lado."},{"tag":"聴く","lbl":"Escuchar con atención","jp":"聴く","rd":"きく","when":"Escuchar concentrado: música, una conferencia. Implica intención.","ex":"クラシックを聴くのが好きです。","exr":"クラシックを きくのが すきです","ext":"Me gusta escuchar música clásica."},{"tag":"訊く","lbl":"Preguntar · interrogar","jp":"訊く","rd":"きく","when":"Preguntar. Kanji poco usado en la práctica: casi siempre se escribe 聞く.","ex":"警察が事情を訊いた。","exr":"けいさつが じじょうを きいた","ext":"La policía preguntó por lo ocurrido."}],"note":"聞ける = tener la oportunidad de escuchar (生の演奏が聞ける). 聞こえる = tener oídos que captan el sonido.","err":"Confundir 聞こえる con 聞ける. 電話の声が聞こえない = no oigo bien (volumen). 聞けない = no puedo escucharlo (no hay ocasión)."},
{"id":"tsukai-omou","cat":"tsukaiwake","lvl":"N3","title":"思う・考える","sub":"Sentir una opinión vs razonar","intro":"思う sale del corazón: una impresión, una creencia. 考える sale de la cabeza: un proceso de razonamiento que lleva tiempo.","rows":[{"tag":"思う","lbl":"Opinión · sentimiento","jp":"思う","rd":"おもう","when":"Creer, opinar, sentir. Espontáneo, subjetivo. Con と para citar el pensamiento.","ex":"彼は正しいと思います。","exr":"かれは ただしいと おもいます","ext":"Creo que él tiene razón."},{"tag":"考える","lbl":"Razonamiento · reflexión","jp":"考える","rd":"かんがえる","when":"Pensar activamente, analizar, planear. Implica esfuerzo mental.","ex":"対策を考えています。","exr":"たいさくを かんがえています","ext":"Estoy pensando en las medidas a tomar."},{"tag":"〜と思っている","lbl":"Opinión mantenida","jp":"思っている","rd":"おもっている","when":"Para opiniones de TERCEROS, el japonés exige 思っている, no 思う.","ex":"彼はそう思っている。","exr":"かれは そう おもっている","ext":"Él piensa así."}],"note":"考えておきます ('lo pensaré') es una fórmula educada para rechazar sin decir que no. 思っておきます no existe.","err":"彼は正しいと思う ✗ para hablar de lo que piensa ÉL. Tu propio pensamiento: 思う. El de otro: 思っている."},
{"id":"tsukai-wakaru","cat":"tsukaiwake","lvl":"N4","title":"分かる・知る","sub":"Comprender vs tener el dato","intro":"知る es adquirir información; 分かる es que esa información te encaje. Además, 分かる lleva が (no を): es un estado, no una acción.","rows":[{"tag":"分かる","lbl":"Comprender · lleva が","jp":"分かる","rd":"わかる","when":"Entender, captar el sentido. Es un estado espontáneo, por eso が.","ex":"意味が分かりません。","exr":"いみが わかりません","ext":"No entiendo el significado."},{"tag":"知る","lbl":"Saber · adquirir el dato","jp":"知る","rd":"しる","when":"Llegar a saber algo. En afirmativo casi siempre 知っている (ya lo sé).","ex":"その店を知っています。","exr":"その みせを しっています","ext":"Conozco esa tienda."},{"tag":"知らない","lbl":"La asimetría clave","jp":"知らない","rd":"しらない","when":"En negativo NO se dice 知っていない: se dice 知らない.","ex":"彼の住所は知りません。","exr":"かれの じゅうしょは しりません","ext":"No sé su dirección."}],"note":"分かりました = 'entendido' (acepto lo que me dices). 知りました casi no se usa: para eso está 知っています.","err":"日本語を分かります ✗ → 日本語が分かります ✓. Y 知っていません ✗ → 知りません ✓."},
{"id":"tsukai-tsukuru","cat":"tsukaiwake","lvl":"N2","title":"作る・造る・創る","sub":"Un sonido, tres escalas de creación","intro":"Los tres se leen つくる. El kanji indica la escala y la naturaleza de lo que fabricas: cotidiano, industrial o artístico.","rows":[{"tag":"作る","lbl":"Cotidiano · genérico","jp":"作る","rd":"つくる","when":"Lo normal: comida, objetos pequeños, planes, reglas. Es el kanji por defecto.","ex":"母が朝ご飯を作ってくれた。","exr":"ははが あさごはんを つくって くれた","ext":"Mi madre me preparó el desayuno."},{"tag":"造る","lbl":"Gran escala · industrial","jp":"造る","rd":"つくる","when":"Construir algo grande o fabricar con proceso: barcos, edificios, sake, carreteras.","ex":"日本酒を造る蔵元。","exr":"にほんしゅを つくる くらもと","ext":"La bodega que elabora sake."},{"tag":"創る","lbl":"Crear de la nada","jp":"創る","rd":"つくる","when":"Crear algo que no existía: arte, una empresa, una cultura. Kanji de 創造 (creación).","ex":"新しい文化を創る。","exr":"あたらしい ぶんかを つくる","ext":"Crear una cultura nueva."}],"note":"En la duda, 作る es siempre aceptable: es el kanji más amplio y nadie lo verá mal.","err":"Usar 創る para cosas triviales suena pretencioso: カレーを創る hace sonreír a un japonés."},
{"id":"tsukai-kiru","cat":"tsukaiwake","lvl":"N4","title":"着る・履く・かぶる・する","sub":"Vestirse: un verbo por cada parte del cuerpo","intro":"El japonés no tiene un 'ponerse' genérico: el verbo cambia según DÓNDE va la prenda. Es una de las primeras cosas que delatan a un principiante.","rows":[{"tag":"着る","lbl":"Tronco","jp":"着る","rd":"きる","when":"Ropa que cubre el torso: camisa, abrigo, kimono, vestido.","ex":"コートを着て出かけた。","exr":"コートを きて でかけた","ext":"Salí con el abrigo puesto."},{"tag":"履く","lbl":"De cintura para abajo","jp":"履く","rd":"はく","when":"Pantalones, falda, calcetines, zapatos.","ex":"新しい靴を履いています。","exr":"あたらしい くつを はいています","ext":"Llevo zapatos nuevos."},{"tag":"かぶる","lbl":"Cabeza","jp":"かぶる","rd":"かぶる","when":"Gorro, sombrero, casco: algo que cubre desde arriba.","ex":"帽子をかぶってください。","exr":"ぼうしを かぶって ください","ext":"Ponte el gorro."},{"tag":"する／かける","lbl":"Accesorios","jp":"する／かける","rd":"する／かける","when":"する: corbata, guantes, reloj, pendientes. かける: gafas (se cuelgan de las orejas).","ex":"眼鏡をかける。／ネクタイをする。","exr":"めがねを かける／ネクタイを する","ext":"Ponerse las gafas. / Ponerse la corbata."},{"tag":"身に着ける","lbl":"Genérico · formal","jp":"身に着ける","rd":"みにつける","when":"Comodín para 'llevar puesto' cualquier cosa. También: adquirir una habilidad.","ex":"制服を身に着ける。／技術を身に付ける。","exr":"せいふくを みに つける","ext":"Llevar el uniforme. / Adquirir una técnica."}],"note":"Para el ESTADO de llevar algo puesto se usa ている: 着ている (lo lleva puesto), no 着た (se lo puso).","err":"ズボンを着る ✗ → ズボンを履く ✓. Los pantalones no se 着る nunca."},
{"id":"tsukai-narau","cat":"tsukaiwake","lvl":"N3","title":"習う・学ぶ・勉強する・教わる","sub":"Aprender de alguien vs por tu cuenta","intro":"La diferencia principal: 習う exige un maestro; 学ぶ y 勉強する no. Y 教わる es el reverso exacto de 教える.","rows":[{"tag":"習う","lbl":"Con un maestro","jp":"習う","rd":"ならう","when":"Aprender una técnica de alguien que te la enseña, normalmente repitiendo: piano, cocina, caligrafía.","ex":"子供の頃、ピアノを習っていました。","exr":"こどもの ころ、ピアノを ならって いました","ext":"De pequeño estudiaba piano (con profesor)."},{"tag":"学ぶ","lbl":"Aprender · formal, amplio","jp":"学ぶ","rd":"まなぶ","when":"Adquirir conocimiento o una lección de vida. Formal, algo literario. No necesita profesor.","ex":"失敗から学ぶことが多い。","exr":"しっぱいから まなぶ ことが おおい","ext":"Se aprende mucho de los fracasos."},{"tag":"勉強する","lbl":"Estudiar · esfuerzo","jp":"勉強する","rd":"べんきょうする","when":"El acto de estudiar, con esfuerzo. El kanji 勉 significa literalmente 'esforzarse'.","ex":"毎日二時間勉強します。","exr":"まいにち にじかん べんきょう します","ext":"Estudio dos horas al día."},{"tag":"教わる","lbl":"Que te enseñen","jp":"教わる","rd":"おそわる","when":"Recibir enseñanza. Es el par intransitivo de 教える, visto desde el alumno.","ex":"先生に漢字を教わりました。","exr":"せんせいに かんじを おそわりました","ext":"El profesor me enseñó kanji."}],"note":"勉強になりました ('ha sido instructivo') es la fórmula educada tras aprender algo de alguien. Muy usada en el trabajo.","err":"独学で習う ✗: 習う implica maestro. Estudiar por tu cuenta es 独学で勉強する / 学ぶ."},
{"id":"tsukai-sumu","cat":"tsukaiwake","lvl":"N3","title":"住む・暮らす・生きる","sub":"Residir, vivir el día a día y estar vivo","intro":"Los tres son 'vivir' en español, pero uno indica dirección, otro estilo de vida y el tercero, existencia biológica.","rows":[{"tag":"住む","lbl":"Residir · dirección","jp":"住む","rd":"すむ","when":"Tener tu domicilio en un lugar. Se usa en ている: 住んでいます.","ex":"東京に住んでいます。","exr":"とうきょうに すんでいます","ext":"Vivo en Tokio."},{"tag":"暮らす","lbl":"Vivir el día a día","jp":"暮らす","rd":"くらす","when":"Llevar una vida (cómoda, sola, con poco dinero). Foco en el modo de vida.","ex":"一人で暮らしています。／楽に暮らしたい。","exr":"ひとりで くらして います","ext":"Vivo solo. / Quiero vivir con holgura."},{"tag":"生きる","lbl":"Estar vivo · existir","jp":"生きる","rd":"いきる","when":"Tener vida, sobrevivir. Existencia biológica o sentido vital.","ex":"百歳まで生きた。／自分らしく生きたい。","exr":"ひゃくさいまで いきた","ext":"Vivió hasta los cien. / Quiero vivir a mi manera."}],"note":"住む casi siempre va en ている. 東京に住みます solo se dice de un plan futuro (voy a mudarme a Tokio).","err":"東京に生きています ✗ para decir dónde resides → 東京に住んでいます ✓."},
{"id":"tsukai-kaeru","cat":"tsukaiwake","lvl":"N4","title":"帰る・戻る・返す","sub":"Volver a casa vs volver a un punto","intro":"帰る tiene destino fijo: tu hogar, tu país, tu base. 戻る es volver a cualquier punto anterior, aunque no sea tuyo.","rows":[{"tag":"帰る","lbl":"Volver a TU sitio","jp":"帰る","rd":"かえる","when":"Volver a casa, al país natal, a tu base. Implica pertenencia.","ex":"今日は早く家に帰ります。","exr":"きょうは はやく いえに かえります","ext":"Hoy vuelvo pronto a casa."},{"tag":"戻る","lbl":"Volver a un punto","jp":"戻る","rd":"もどる","when":"Regresar a un lugar donde estabas antes, o a un estado anterior. Sin matiz de hogar.","ex":"すぐ席に戻ります。／元に戻った。","exr":"すぐ せきに もどります","ext":"Vuelvo enseguida a mi sitio. / Volvió a ser como antes."},{"tag":"返す","lbl":"Devolver algo","jp":"返す","rd":"かえす","when":"Devolver un objeto a su dueño. Transitivo (el par intransitivo es 返る).","ex":"図書館に本を返しました。","exr":"としょかんに ほんを かえしました","ext":"Devolví el libro a la biblioteca."}],"note":"En la oficina, 戻ります indica que volverás; 帰ります indica que te vas a casa (terminas la jornada). Confundirlos causa malentendidos reales.","err":"Decir 帰ります al salir un momento de una reunión: tus compañeros entenderán que te vas a casa. Di 戻ります."},
{"id":"tsukai-tsukau","cat":"tsukaiwake","lvl":"N2","title":"使う・用いる・利用する・活用する","sub":"Cuatro registros de 'usar'","intro":"Desde el 使う de todos los días hasta el 活用する de un informe. Elegir bien marca la diferencia entre sonar natural o sonar traducido.","rows":[{"tag":"使う","lbl":"Genérico · cotidiano","jp":"使う","rd":"つかう","when":"Usar cualquier cosa. El comodín.","ex":"このペンを使ってもいいですか。","exr":"この ペンを つかっても いいですか","ext":"¿Puedo usar este boli?"},{"tag":"用いる","lbl":"Formal · escrito","jp":"用いる","rd":"もちいる","when":"Emplear. Registro escrito, académico. Casi nunca en conversación.","ex":"この研究では新しい手法を用いた。","exr":"この けんきゅうでは あたらしい しゅほうを もちいた","ext":"En este estudio se empleó un método nuevo."},{"tag":"利用する","lbl":"Aprovechar un servicio","jp":"利用する","rd":"りようする","when":"Usar algo que existe para tu beneficio: transporte, instalaciones, un sistema. También 'aprovecharse de alguien'.","ex":"駅の駐輪場を利用しています。","exr":"えきの ちゅうりんじょうを りよう しています","ext":"Uso el aparcamiento de bicis de la estación."},{"tag":"活用する","lbl":"Sacar todo el partido","jp":"活用する","rd":"かつようする","when":"Usar algo al máximo de su potencial: recursos, conocimientos, tecnología. Tono positivo.","ex":"経験を活用して新しい仕事に挑戦する。","exr":"けいけんを かつよう して あたらしい しごとに ちょうせん する","ext":"Aprovechar la experiencia para afrontar un trabajo nuevo."}],"note":"活用 también es el término gramatical para 'conjugación' de un verbo: 動詞の活用.","err":"人を利用する tiene matiz negativo (aprovecharse de alguien). Para 'contar con alguien' es 頼る."},
{"id":"tsukai-naru","cat":"tsukaiwake","lvl":"N4","title":"〜になる・〜にする","sub":"Se convierte solo vs yo lo decido","intro":"La misma lógica de 自動詞/他動詞 aplicada al cambio: なる es el cambio que ocurre, する es el cambio que provocas. En un restaurante, es la diferencia entre describir y pedir.","rows":[{"tag":"〜になる","lbl":"Cambio natural","jp":"〜になる","rd":"〜に なる","when":"Algo se convierte en otra cosa por sí mismo. Nadie lo decide.","ex":"来年、二十歳になります。／医者になりたい。","exr":"らいねん、はたちに なります","ext":"El año que viene cumplo veinte. / Quiero ser médico."},{"tag":"〜にする","lbl":"Decisión propia","jp":"〜にする","rd":"〜に する","when":"Alguien decide o transforma algo. En restaurantes: elegir.","ex":"私はコーヒーにします。／部屋をきれいにした。","exr":"わたしは コーヒーに します","ext":"Yo tomaré café. / Dejé la habitación limpia."},{"tag":"〜ことになる","lbl":"Se ha decidido (impersonal)","jp":"〜ことになる","rd":"〜ことに なる","when":"Una decisión tomada por otros o por las circunstancias. Muy usado para suavizar.","ex":"来月、大阪に転勤することになりました。","exr":"らいげつ、おおさかに てんきん する ことに なりました","ext":"Me trasladan a Osaka el mes que viene."},{"tag":"〜ことにする","lbl":"Lo decido yo","jp":"〜ことにする","rd":"〜ことに する","when":"Tú tomas la decisión conscientemente.","ex":"毎朝走ることにしました。","exr":"まいあさ はしる ことに しました","ext":"He decidido correr cada mañana."}],"note":"El japonés prefiere ことになりました aunque la decisión sea tuya: presentar tus decisiones como circunstancias suena más humilde.","err":"En un restaurante, コーヒーになります (muy oído en tiendas) es 'keigo de manual' criticado: lo correcto es コーヒーでございます."},
{"id":"tsukai-ageru-kureru","cat":"tsukaiwake","lvl":"N4","title":"〜てあげる・〜てくれる・〜てもらう","sub":"Favores: la dirección importa más que el verbo","intro":"Cuando el favor va en forma て, el japonés SIEMPRE marca la dirección. Omitirlo hace que la frase suene fría o incluso maleducada.","rows":[{"tag":"〜てあげる","lbl":"Yo hago por otro","jp":"〜てあげる","rd":"〜て あげる","when":"Haces un favor a alguien. Ojo: dicho al beneficiario suena condescendiente.","ex":"友達に日本語を教えてあげた。","exr":"ともだちに にほんごを おしえて あげた","ext":"Le enseñé japonés a un amigo."},{"tag":"〜てくれる","lbl":"Otro hace por mí","jp":"〜てくれる","rd":"〜て くれる","when":"Alguien te hace un favor a TI. Expresa gratitud implícita.","ex":"友達が手伝ってくれました。","exr":"ともだちが てつだって くれました","ext":"Un amigo me ayudó."},{"tag":"〜てもらう","lbl":"Yo recibo el favor","jp":"〜てもらう","rd":"〜て もらう","when":"Mismo hecho que くれる, pero tú eres el sujeto. Suele implicar que lo pediste.","ex":"友達に手伝ってもらいました。","exr":"ともだちに てつだって もらいました","ext":"Hice que un amigo me ayudara / Me ayudó un amigo."},{"tag":"〜ていただけますか","lbl":"Petición muy cortés","jp":"〜ていただけますか","rd":"〜て いただけますか","when":"La forma educada de pedir algo. Potencial de いただく: '¿podría recibir el favor de…?'","ex":"少々お待ちいただけますか。","exr":"しょうしょう おまち いただけますか","ext":"¿Podría esperar un momento?"}],"note":"Escala de cortesía al pedir: 〜て → 〜てください → 〜てくれますか → 〜てもらえますか → 〜ていただけますか → 〜ていただけませんでしょうか.","err":"荷物を持ってあげましょうか a un superior suena a favor concedido desde arriba. Lo correcto: お持ちしましょうか."},
{"id":"tsukai-shiru-keiken","cat":"tsukaiwake","lvl":"N2","title":"〜ておく・〜てある・〜ている","sub":"Preparar, dejar hecho y estar así","intro":"Tres formas て que hablan de estados y preparativos. La clave: quién actúa y si la intención sigue viva.","rows":[{"tag":"〜ておく","lbl":"Dejar hecho de antemano","jp":"〜ておく","rd":"〜て おく","when":"Hacer algo por adelantado, preparando el futuro. En habla casual: 〜とく.","ex":"会議の前に資料を読んでおきます。","exr":"かいぎの まえに しりょうを よんで おきます","ext":"Leeré los documentos antes de la reunión."},{"tag":"〜てある","lbl":"Estado dejado a propósito","jp":"〜てある","rd":"〜て ある","when":"Con TRANSITIVO: alguien lo hizo y el resultado sigue ahí, con intención. La cosa lleva が.","ex":"壁に絵が掛けてある。","exr":"かべに えが かけてある","ext":"Hay un cuadro colgado en la pared (alguien lo colgó)."},{"tag":"〜ている","lbl":"Estado o acción en curso","jp":"〜ている","rd":"〜て いる","when":"Con INTRANSITIVO: el estado resultante. Con transitivo: acción en curso.","ex":"窓が開いている。／今、本を読んでいる。","exr":"まどが あいている／いま、ほんを よんでいる","ext":"La ventana está abierta. / Ahora estoy leyendo."}],"note":"掛けてある (alguien lo colgó, hay intención) vs 掛かっている (está colgado, sin más). El japonés distingue lo que en español es solo 'está colgado'.","err":"Usar 〜てある con intransitivos: 窓が開いてある ✗. Solo transitivos admiten てある → 窓が開けてある ✓."}
];
